import { useState, useEffect } from "react";
import "./Recruitment.css";

function ViewByRole() {

  const [designations, setDesignations] = useState([]);
  const [employees, setEmployees] = useState([]);
  const [selectedRole, setSelectedRole] = useState("");

  // Load data
  useEffect(() => {
    const roles = JSON.parse(localStorage.getItem("designations")) || [];
    const emps = JSON.parse(localStorage.getItem("employees")) || [];

    setDesignations(roles);
    setEmployees(emps);
  }, []);

  const filteredEmployees = selectedRole
    ? employees.filter(e => e.designation === selectedRole)
    : [];

  return (
    <div className="designation-container">
      <h2>View Employees By Designation</h2>

      {/* Dropdown */}
      <div className="designation-form">
        <select
          value={selectedRole}
          onChange={(e) => setSelectedRole(e.target.value)}
        >
          <option value="">Select Designation</option>

          {designations.map(d => (
            <option key={d.id} value={d.title}>
              {d.title}
            </option>
          ))}
        </select>
      </div>

      {/* Table */}
      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Name</th>
            <th>Email</th>
            <th>Salary</th>
            <th>Designation</th>
          </tr>
        </thead>

        <tbody>
          {filteredEmployees.length === 0 ? (
            <tr>
              <td colSpan="5">No Employees Found</td>
            </tr>
          ) : (
            filteredEmployees.map((e, index) => (
              <tr key={e.id}>
                <td>{index + 1}</td>
                <td>{e.firstName} {e.lastName}</td>
                <td>{e.email}</td>
                <td>{e.salary}</td>
                <td>{e.designation}</td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

export default ViewByRole;
